const payload = $json.payload || {};
const customerName = payload.customer_name || 'Customer';
const providerName = payload.provider_name || 'Provider';
const orderCode = payload.order_code || 'N/A';
const estimatedPrice = payload.estimated_price ?? 0;
const dpAmount = payload.dp_amount ?? 0;
const customerEmail = payload.customer_email || '';
const providerEmail = payload.provider_email || '';

return [
  {
    json: {
      email: customerEmail,
      recipient_type: 'customer',
      subject: `Pesanan ${orderCode} - TukangDekat`,
      html: `<h2>Halo ${customerName},</h2><p>Pesanan Anda dengan kode <strong>${orderCode}</strong> telah berhasil dibuat di TukangDekat.</p><p><strong>Detail Pesanan:</strong></p><ul><li>Kode Order: ${orderCode}</li><li>Estimasi Harga: Rp ${estimatedPrice}</li><li>Total DP: Rp ${dpAmount}</li></ul><p>Silakan tunggu konfirmasi dari provider. Anda akan menerima notifikasi lanjutan segera.</p><p>Terima kasih,<br>Tim TukangDekat</p>`
    }
  },
  {
    json: {
      email: providerEmail,
      recipient_type: 'provider',
      subject: `Order Baru ${orderCode} - TukangDekat`,
      html: `<h2>Halo ${providerName},</h2><p>Ada order baru untuk Anda dengan kode <strong>${orderCode}</strong>.</p><p><strong>Detail Pesanan:</strong></p><ul><li>Kode Order: ${orderCode}</li><li>Estimasi Harga: Rp ${estimatedPrice}</li><li>Total DP: Rp ${dpAmount}</li></ul><p>Silakan login ke dashboard TukangDekat untuk melihat detail lengkap dan segera lakukan respons.</p><p>Terima kasih,<br>Tim TukangDekat</p>`
    }
  }
];

const payload = $json.payload || {};
const customerName = payload.customer_name || 'Customer';
