  }
}];

const payload = $json.payload || {};
const customerName = payload.customer_name || 'Customer';
const customerEmail = payload.customer_email || '';
const orderCode = payload.order_code || 'N/A';
const reason = payload.reason || payload.rejection_reason || 'Tidak ada alasan yang diberikan';

return [{
  json: {
    email: customerEmail,
    recipient_type: 'customer',
    subject: `Pesanan ${orderCode} Ditolak - TukangDekat`,
    html: `<h2>Halo ${customerName},</h2><p>Maaf, pesanan Anda dengan kode <strong>${orderCode}</strong> ditolak oleh provider.</p><p><strong>Alasan Penolakan:</strong></p><p>${reason}</p><p>Silakan membuat order baru atau hubungi tim support kami untuk bantuan lebih lanjut.</p><p>Terima kasih,<br>Tim TukangDekat</p>`
  }
}];

const payload = $json.payload || {};
const orderCode = payload.order_code || 'N/A';
const amount = payload.amount || payload.dp_amount || 0;
const customerName = payload.customer_name || 'Customer';
const providerName = payload.provider_name || 'Provider';
const customerEmail = payload.customer_email || '';
const providerEmail = payload.provider_email || '';

return [
  {
    json: {
      email: customerEmail,
      recipient_type: 'customer',
      subject: `DP Pesanan ${orderCode} Diterima - TukangDekat`,
      html: `<h2>Halo ${customerName},</h2><p>Pembayaran DP sebesar <strong>Rp ${amount}</strong> untuk pesanan <strong>${orderCode}</strong> telah kami terima dan dicatat.</p><p>Provider akan segera memulai persiapan pekerjaan. Anda akan menerima notifikasi lebih lanjut.</p><p>Terima kasih,<br>Tim TukangDekat</p>`
    }
  },
  {
    json: {
      email: providerEmail,
      recipient_type: 'provider',
      subject: `DP Diterima untuk Pesanan ${orderCode} - TukangDekat`,
      html: `<h2>Halo ${providerName},</h2><p>DP sebesar <strong>Rp ${amount}</strong> untuk pesanan <strong>${orderCode}</strong> telah diterima oleh customer.</p><p>Silakan persiapkan pekerjaan dan lakukan konfirmasi jadwal kepada customer. Update status pekerjaan di dashboard.</p><p>Terima kasih,<br>Tim TukangDekat</p>`
    }
  }
];

const payload = $json.payload || {};
