const providerName = payload.provider_name || 'Provider';
const customerEmail = payload.customer_email || '';
const providerEmail = payload.provider_email || '';

return [
  {
    json: {
      email: customerEmail,
      recipient_type: 'customer',
      subject: `Pesanan ${orderCode} Selesai - TukangDekat`,
      html: `<h2>Halo ${customerName},</h2><p>Pembayaran final sebesar <strong>Rp ${amount}</strong> untuk pesanan <strong>${orderCode}</strong> telah berhasil kami terima.</p><p>Pesanan Anda sekarang ditutup. Terima kasih telah menggunakan layanan TukangDekat. Kami menunggu rating dan review Anda untuk provider.</p><p>Terima kasih,<br>Tim TukangDekat</p>`
    }
  },
  {
    json: {
      email: providerEmail,
      recipient_type: 'provider',
      subject: `Pembayaran Final Pesanan ${orderCode} Selesai - TukangDekat`,
      html: `<h2>Halo ${providerName},</h2><p>Pembayaran final sebesar <strong>Rp ${amount}</strong> untuk pesanan <strong>${orderCode}</strong> telah berhasil diterima dari customer.</p><p>Pesanan ini sekarang ditutup. Terima kasih atas kerja keras Anda. Pantau rating customer di dashboard profil Anda.</p><p>Terima kasih,<br>Tim TukangDekat</p>`
    }
  }
];
